-- Synthetic GPA Results Database for RTU B.Tech Students
-- Generated automatically by Antigravity AI agent

DROP TABLE IF EXISTS student_subject_results;
DROP TABLE IF EXISTS student_results;

CREATE TABLE student_results (
    enrollment_no VARCHAR(50) PRIMARY KEY,
    sem1_gpa NUMERIC(4, 2),
    sem2_gpa NUMERIC(4, 2),
    sem3_gpa NUMERIC(4, 2),
    sem4_gpa NUMERIC(4, 2),
    sem5_gpa NUMERIC(4, 2),
    sem6_gpa NUMERIC(4, 2),
    sem7_gpa NUMERIC(4, 2),
    sem8_gpa NUMERIC(4, 2),
    cgpa NUMERIC(4, 2)
);

CREATE TABLE student_subject_results (
    id SERIAL PRIMARY KEY,
    enrollment_no VARCHAR(50) NOT NULL REFERENCES student_results(enrollment_no) ON DELETE CASCADE,
    semester INT NOT NULL,
    subject_name VARCHAR(150) NOT NULL,
    gpa NUMERIC(4, 2) NOT NULL,
    UNIQUE (enrollment_no, semester, subject_name)
);

